// app/(admin)/layout.tsx
"use client"
import { useIsMobile } from "@/hooks/use-mobile"
import { useState } from "react"
import Sidebar from "@/components/dashboard/Sidebar"
import { cn } from "@/lib/utils" 

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const [collapsed, setCollapsed] = useState(false)
  const isMobile = useIsMobile()

  // Datos de ejemplo (luego vendrán de tu base de datos)
  const stats = {
    totalRolls: 24,
    totalClients: 85,
    activeOrders: 3
  }

  return (
    <div className={cn(
    "flex-1 w-full transition-all duration-300",
    // IMPORTANTE: En móvil NO debe tener margen izquierdo. 
    // Solo en PC (lg:) debe dejarle el lugar al sidebar.
    isMobile ? "pt-16 px-4" : (collapsed ? "ml-[72px] p-8" : "ml-[260px] p-8")
  )}>
      <Sidebar 
        collapsed={collapsed}
        onToggleCollapse={() => setCollapsed(!collapsed)}
        stats={stats}
      />
      <main className="flex-1 overflow-y-auto p-8">
        {children}
      </main>
    </div>
  )
}