"use client"
import { useState } from "react"
import Link from "next/link"
import { Menu, X, Package, Home, Settings, LogOut } from "lucide-react"

export default function Sidebar() {
  const [isOpen, setIsOpen] = useState(false)

  const menuItems = [
    { name: "Dashboard", href: "/gestion", icon: <Home size={22} /> },
    { name: "Inventario", href: "/gestion/inventario", icon: <Package size={22} /> },
    { name: "Ajustes", href: "/gestion/config", icon: <Settings size={22} /> },
  ]

  return (
    <>
      {/* BOTÓN FLOTANTE - Solo visible en móvil (S9) */}
      <button 
        onClick={() => setIsOpen(true)}
        className="lg:hidden fixed top-4 left-4 z-50 p-2 bg-[#c9a961] text-black rounded-md shadow-lg"
      >
        <Menu size={24} />
      </button>

      {/* OVERLAY - Fondo oscuro cuando el sidebar está abierto en el celular */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-black/60 z-[60] lg:hidden backdrop-blur-sm"
          onClick={() => setIsOpen(false)}
        />
      )}

      {/* SIDEBAR */}
      <aside className={`
        fixed top-0 left-0 h-full z-[70]
        bg-[#0a0a0a] border-r border-[#c9a961]/20
        transition-transform duration-300 ease-in-out
        w-64
        ${isOpen ? "translate-x-0" : "-translate-x-full"} 
        lg:translate-x-0 lg:static
      `}>
        <div className="flex flex-col h-full p-6">
          {/* Cabecera Sidebar */}
          <div className="flex justify-between items-center mb-10">
            <h2 className="text-[#c9a961] font-serif text-xl tracking-tighter">
              AMARIGOM <span className="block text-[10px] tracking-[4px] opacity-70">DECO</span>
            </h2>
            <button onClick={() => setIsOpen(false)} className="lg:hidden text-[#c9a961]">
              <X size={24} />
            </button>
          </div>

          {/* Links del Menú */}
          <nav className="flex-1 space-y-2">
            {menuItems.map((item) => (
              <Link
                key={item.name}
                href={item.href}
                onClick={() => setIsOpen(false)}
                className="flex items-center gap-4 px-4 py-3 text-gray-400 hover:text-[#c9a961] hover:bg-[#c9a961]/5 rounded-lg transition-all group"
              >
                <span className="group-hover:scale-110 transition-transform">{item.icon}</span>
                <span className="font-medium">{item.name}</span>
              </Link>
            ))}
          </nav>

          {/* Footer Sidebar */}
          <div className="pt-6 border-t border-[#c9a961]/10">
            <button className="flex items-center gap-4 px-4 py-2 text-red-400/70 hover:text-red-400 transition-colors w-full">
              <LogOut size={20} />
              <span>Salir</span>
            </button>
          </div>
        </div>
      </aside>
    </>
  )
}